+}
+
+type FrameBoundaryKind = 'unbounded preceding' | 'preceding' | 'current row' | 'following' | 'unbounded following';
+
+export interface FrameBoundary {
+	readonly kind: FrameBoundaryKind;
+	readonly value?: number;
+}
+
+export interface WindowFrame {
+	readonly type: 'rows' | 'range';
+	readonly from: FrameBoundary;
+	readonly to: FrameBoundary;
+}
+
+export const unboundedPreceding: FrameBoundary = { kind: 'unbounded preceding' };
+export const currentRow: FrameBoundary = { kind: 'current row' };
+export const unboundedFollowing: FrameBoundary = { kind: 'unbounded following' };
+
+function validateBoundaryValue(helper: string, value: number): void {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${helper}() expects a non-negative integer, received ${value}`);
+	}
+}
+
+export function preceding(value: number): FrameBoundary {
+	validateBoundaryValue('preceding', value);
+	return { kind: 'preceding', value };
+}
+
+export function following(value: number): FrameBoundary {
+	validateBoundaryValue('following', value);
+	return { kind: 'following', value };
+}
+
+function boundaryPosition(boundary: FrameBoundary): number {
+	switch (boundary.kind) {
+		case 'unbounded preceding': return Number.NEGATIVE_INFINITY;
+		case 'preceding': return -boundary.value!;
+		case 'current row': return 0;
+		case 'following': return boundary.value!;
+		case 'unbounded following': return Number.POSITIVE_INFINITY;
+	}
+}
+
+function makeFrame(type: WindowFrame['type'], frame: { from: FrameBoundary; to: FrameBoundary }): WindowFrame {
+	if (boundaryPosition(frame.from) > boundaryPosition(frame.to)) {
+		throw new Error('Window frame "from" boundary must not be ordered after "to" boundary');
+	}
+	return { type, ...frame };
+}
+
+export function rows(frame: { from: FrameBoundary; to: FrameBoundary }): WindowFrame {
+	return makeFrame('rows', frame);
+}
+
+export function range(frame: { from: FrameBoundary; to: FrameBoundary }): WindowFrame {
+	return makeFrame('range', frame);
+}
+
+function renderBoundary(boundary: FrameBoundary): SQL {
+	return boundary.value === undefined ? sql.raw(boundary.kind) : sql.raw(`${boundary.value} ${boundary.kind}`);
+}
+
+/** @internal */
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const chunks: SQL[] = [];
+	const partitionBy = spec.partitionBy === undefined ? [] : Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy];
+	const orderBy = spec.orderBy === undefined ? [] : Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy];
+	if (partitionBy.length) chunks.push(sql`partition by ${sql.join(partitionBy, sql`, `)}`);
+	if (orderBy.length) chunks.push(sql`order by ${sql.join(orderBy, sql`, `)}`);
+	if (spec.frame) chunks.push(sql`${sql.raw(spec.frame.type)} between ${renderBoundary(spec.frame.from)} and ${renderBoundary(spec.frame.to)}`);
+	return sql.join(chunks, sql` `);
+}
+
+export class WindowFunction<T> implements SQLWrapper {
+	constructor(private readonly expression: SQL<T>) {}
+
+	getSQL(): SQL {
+		return this.expression;
+	}
+
+	over(spec: WindowSpec | string = {}): SQL<T> {
+		if (typeof spec === 'string') return sql`${this.expression} over ${name(spec)}`;
+		return sql`${this.expression} over (${buildWindowSpec(spec)})`;
+	}
+}
+
+function windowFunction<T>(functionName: string, args: SQLWrapper[] = []): WindowFunction<T> {
+	return new WindowFunction(sql`${sql.raw(functionName)}(${sql.join(args, sql`, `)})`);
+}
+
+function positionalArgument(functionName: string, value: number): SQL {
+	if (!Number.isInteger(value) || value <= 0) {
+		throw new Error(`${functionName}() expects a positive integer, received ${value}`);
+	}
+	return sql.raw(String(value));
+}
